#include <stdbool.h>

#define MaxSize 50
#define NIL -1
#define FREE -2

typedef int ElemType;

typedef struct {
    ElemType data;
    int next;       // 游标：下一个结点的数组下标
} SNode;

typedef SNode SLinkList[MaxSize];

void InitSLinkList(SLinkList L) {
    L[0].next = NIL;       // 0 号单元作为头结点
    for (int i = 1; i < MaxSize; ++i) {
        L[i].next = FREE;  // 标记为空闲结点
    }
}

int FindFree(SLinkList L) {
    for (int i = 1; i < MaxSize; ++i) {
        if (L[i].next == FREE) {
            return i;
        }
    }
    return NIL;
}
